var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"먼저 제안을 해올 줄은 몰랐는데, 의외네.","JPN":"お前から提案してくるなんて、意外だね。","ENG":"I didn't think you'd make an offer first.","TWN":"沒想到你會先說出了這個提議，真意外。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"한낱 도구일 뿐인 나한테 이렇게 극진한 대접을 해주다니......","JPN":"単なる道具にすぎない私に、こんな手厚いもてなしをしてくれるなんて……","ENG":"You're treating me so nicely even though I'm just a tool.","TWN":"對於像是工具般的我，竟然給予如此無微不至的待遇…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"하긴, 기계도 사람처럼 대하는 걸 보면 딱히 이상할 것도 없긴 해.","JPN":"まあ、機械も人間と同じように接しているところを見ると、特に変じゃないか。","ENG":"Then again, you even treat machines like people. This isn't that strange.","TWN":"看來也是，老闆對公司的機器也給予像人一樣對待了，現在這樣好像也沒什麼奇怪的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"답례라고 하긴 그렇지만…… 이제 나도 당신에게 신뢰를 보여 줄 필요가 있겠네.","JPN":"お礼と言ってはなんだけど……これからは私もお前に対する信頼を示す必要があるね。","ENG":"I don't want to say thanks, but... I feel the need to reciprocate your trust.","TWN":"雖不能說是一種回禮… 現在我也需要向你表達該有的信任了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"좋아. 앞으로는 사적인 일에도 되도록이면 협조해 주기로 할게.","JPN":"いいよ。これからはプライベートなことでもなるべく協力してあげる。","ENG":"Okay, I'll do my best to cooperate with you, even in a personal capacity.","TWN":"好。以後在私生活中也會盡量配合老闆的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"예를 들어, 서로 등을 맞대고 같은 음악을 듣는다거나 말이야.","JPN":"例えば、お互い背中合わせして同じ音楽を聴くとか。","ENG":"For instance, you can ask me to listen to music with you, sitting back to back.","TWN":"比如說，互相背靠著背的姿勢聽著同一首音樂。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"……왜? 별로야?","JPN":"……何？気に入らないの？","ENG":"... What? Wouldn't you like that?","TWN":"……怎麼？這樣不好嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"뭐, 신뢰하지 않던 사람에게 등을 맡기려면 우선 맞댈 수 있어야 하지 않겠어?","JPN":"まあ、信頼してなかった人に背中を預けるには、まずやってみる必要があるね。","ENG":"Well, I can't trust someone with my back in battle if I can't trust him out of it.","TWN":"把背後交給人之前，是不是應該先面對面確認對方是否可以信賴？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"친해지고 싶다면, 친한 척부터 시작해야지.","JPN":"仲良くなりたければ、仲良しのふりから始めないと。","ENG":"If you want to be friends with me, then start pretending first.","TWN":"如果想讓彼此更親近，就應該先假裝親近。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"내 제안을 받아들일지 말지는 당신 선택이야.","JPN":"私の提案を受け入れるかどうかは、お前次第だ。","ENG":"It's up to you to accept my suggestion.","TWN":"是否接受我這樣的提議是由你來做選擇。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_UNIT_NULL","text":{"KOREA":"어차피 여기선 남는 게 시간이니까. 느긋하게 기다려 줄게.","JPN":"どうせここでは時間を持て余してるから、ゆっくり待ってあげるよ。","ENG":"I've got nothing but time. I'll wait for you.","TWN":"反正在這裡剩下的時間多著呢，我會慢慢等你的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_UNIT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};